import{_ as n,c as i,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Schnellstart mit AI App Factory: Von Installation zur ersten Anwendung | agent-app-factory","description":"Lernen Sie, wie Sie AI App Factory schnell starten, von der Installation und Konfiguration der CLI-Tools bis zum Verständnis der 7-Phasen-Pipeline. Dieses Kapitel umfasst vier Kernlektionen: Schnellstart, Installation, Projektinitialisierung und Pipeline-Übersicht, die Ihnen helfen, den End-to-End-Automatisierungsprozess von der Idee bis zur ausführbaren Anwendung umfassend zu verstehen.","frontmatter":{"title":"Schnellstart mit AI App Factory: Von Installation zur ersten Anwendung | agent-app-factory","sidebarTitle":"Schnellstart","subtitle":"Schnellstart","description":"Lernen Sie, wie Sie AI App Factory schnell starten, von der Installation und Konfiguration der CLI-Tools bis zum Verständnis der 7-Phasen-Pipeline. Dieses Kapitel umfasst vier Kernlektionen: Schnellstart, Installation, Projektinitialisierung und Pipeline-Übersicht, die Ihnen helfen, den End-to-End-Automatisierungsprozess von der Idee bis zur ausführbaren Anwendung umfassend zu verstehen.","order":10},"headers":[],"relativePath":"de/hyz1992/agent-app-factory/start/index.md","filePath":"de/hyz1992/agent-app-factory/start/index.md"}'),a={name:"de/hyz1992/agent-app-factory/start/index.md"};function s(l,e,o,d,u,h){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="schnellstart" tabindex="-1">Schnellstart <a class="header-anchor" href="#schnellstart" aria-label="Permalink to &quot;Schnellstart&quot;">​</a></h1><p>Dieses Kapitel hilft Ihnen, AI App Factory schnell zu starten, den Kernwert zu verstehen, die Tools zu installieren und zu konfigurieren sowie die Funktionsweise der 7-Phasen-Pipeline zu begreifen, um sich auf die Generierung Ihrer ersten Anwendung vorzubereiten.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Es wird empfohlen, den Inhalt dieses Kapitels in der folgenden Reihenfolge zu erlernen:</p><h3 id="_1-schnellstart-von-der-idee-zur-anwendung" tabindex="-1">1. <a href="./../../getting-started/">Schnellstart: Von der Idee zur Anwendung</a> <a class="header-anchor" href="#_1-schnellstart-von-der-idee-zur-anwendung" aria-label="Permalink to &quot;1. [Schnellstart: Von der Idee zur Anwendung](../../getting-started/)&quot;">​</a></h3><p>Lernen Sie den Kernwert und die Voraussetzungen von AI App Factory kennen und erleben Sie durch ein vollständiges Beispiel den End-to-End-Prozess von der Idee bis zur Anwendung.</p><ul><li>Verstehen des Checkpoint-basierten Multi-Agent-Kooperationsmechanismus</li><li>Verstehen des vollständigen Arbeitsablaufs der 7-Phasen-Pipeline</li><li>Beherrschen der Techniken für klare Produktbeschreibungen</li></ul><h3 id="_2-installation-und-konfiguration" tabindex="-1">2. <a href="./../../installation/">Installation und Konfiguration</a> <a class="header-anchor" href="#_2-installation-und-konfiguration" aria-label="Permalink to &quot;2. [Installation und Konfiguration](../../installation/)&quot;">​</a></h3><p>Installieren Sie das CLI-Tool global und konfigurieren Sie den AI-Assistenten (Claude Code/OpenCode) sowie die zugehörige Umgebung.</p><ul><li>Globale Installation von agent-app-factory über npm</li><li>Konfiguration von Claude Code oder OpenCode</li><li>Überprüfung der erfolgreichen Installation</li></ul><h3 id="_3-factory-projekt-initialisieren" tabindex="-1">3. <a href="./../../init-project/">Factory-Projekt initialisieren</a> <a class="header-anchor" href="#_3-factory-projekt-initialisieren" aria-label="Permalink to &quot;3. [Factory-Projekt initialisieren](../../init-project/)&quot;">​</a></h3><p>Initialisieren Sie das Verzeichnis mit dem Befehl <code>factory init</code> und verstehen Sie die generierte Projektstruktur und Konfigurationsdateien.</p><ul><li>Ausführen des Projektinitialisierungsbefehls</li><li>Verstehen der Projektverzeichnisstruktur und Konfigurationsdateien</li><li>Vorbereiten der Produktidee-Eingabe</li></ul><h3 id="_4-ubersicht-uber-die-7-phasen-pipeline" tabindex="-1">4. <a href="./../../pipeline-overview/">Übersicht über die 7-Phasen-Pipeline</a> <a class="header-anchor" href="#_4-ubersicht-uber-die-7-phasen-pipeline" aria-label="Permalink to &quot;4. [Übersicht über die 7-Phasen-Pipeline](../../pipeline-overview/)&quot;">​</a></h3><p>Vertiefen Sie Ihr Verständnis des vollständigen Pipeline-Prozesses von Bootstrap bis Preview, der Eingaben und Ausgaben der einzelnen Phasen sowie des Checkpoint-Mechanismus.</p><ul><li>Verstehen der Ziele und Ergebnisse der 7 Phasen</li><li>Beherrschen des Checkpoint-Mechanismus und des manuellen Bestätigungsprozesses</li><li>Lernen, wie Sie die Pipeline-Ausführung steuern</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie mit diesem Kapitel beginnen, benötigen Sie:</p><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen</p><ol><li><strong>Node.js-Umgebung</strong>: Node.js v18 oder höher ist installiert</li><li><strong>KI-Programmierassistent</strong>: Eines der folgenden Tools muss konfiguriert sein <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> (empfohlen) ⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> oder ein anderer KI-Assistent mit Agent-Modus</li></ul></li><li><strong>Grundlegende Befehlszeilenoperationen</strong>: Fähigkeit, Befehle im Terminal auszuführen</li></ol></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels werden Sie folgendes beherrschen:</p><ul><li>✅ Die Kernarbeitsweise von AI App Factory</li><li>✅ Installation und Konfiguration des CLI-Tools</li><li>✅ Projektinitialisierung und Verständnis der Struktur</li><li>✅ Der vollständige Ablauf der 7-Phasen-Pipeline</li></ul><p>Als Nächstes wird empfohlen, das Kapitel <strong><a href="./../../../platforms/">Plattformen und Integrationen</a></strong> zu erlernen, um zu verstehen, wie Sie die Pipeline auf verschiedenen KI-Assistenten ausführen.</p>',23)])])}const g=n(a,[["render",s]]);export{c as __pageData,g as default};
